FROM nextjs_shop_user_coupon uc
WHERE uc.user_no = #{userNo}
AND uc.coupon_id IN

	#{couponId}

mapper.delete:
DELETE FROM nextjs_shop_stock_hold_coupon
WHERE hold_id IN

	#{holdId}

mapper.select:
SELECT MAX(created_at)
FROM nextjs_shop_stock_hold
WHERE user_no = #{userNo}

SELECT uc.user_coupon_id, c.coupon_id, c.description, c.discount_type, c.discount_value, c.max_discount, c.minimum_order_before_amount, c.is_stackable, c.is_product_restricted, c.amount, c.start_date, c.end_date, c.issue_method, ca.coupon_allowed_id, ca.product_id FROM nextjs_shop_user_coupon uc JOIN nextjs_shop_coupon c ON uc.coupon_id = c.coupon_id LEFT JOIN nextjs_shop_coupon_allowed ca ON ca.coupon_id = c.coupon_id AND ca.product_id IN
#{productId}
WHERE uc.user_no = #{userNo} AND uc.used = 0 AND c.seller_no IS NULL AND c.admin_no IS NOT NULL AND c.is_deleted = 0 AND c.status = 'ACTIVE' AND c.amount > 0 AND ( c.is_product_restricted = 0 OR ca.product_id IS NOT NULL ) AND ( c.issue_method = 'CLAIM' OR (c.issue_method IN ('MANUAL','AUTO') AND uc.user_coupon_id IS NOT NULL) )

SELECT uc.user_coupon_id, c.coupon_id, c.description, c.discount_type, c.discount_value, c.max_discount, c.minimum_order_before_amount, c.is_stackable, c.is_product_restricted, c.amount, c.start_date, c.end_date, c.issue_method, ca.coupon_allowed_id, ca.product_id, s.seller_name FROM nextjs_shop_user_coupon uc JOIN nextjs_shop_coupon c ON uc.coupon_id = c.coupon_id AND uc.used = 0 JOIN nextjs_shop_product p ON c.seller_no = p.seller_no AND p.product_id IN
#{productId}
LEFT JOIN nextjs_shop_coupon_allowed ca ON ca.coupon_id = c.coupon_id AND ca.product_id = p.product_id JOIN nextjs_shop_seller s ON c.seller_no = s.seller_no WHERE uc.user_no = #{userNo} AND c.is_deleted = 0 AND c.status = 'ACTIVE' AND c.amount > 0 AND ( c.is_product_restricted = 0 OR ca.product_id IS NOT NULL ) AND ( c.issue_method = 'CLAIM' OR (c.issue_method IN ('MANUAL','AUTO') AND uc.user_coupon_id IS NOT NULL) )

SELECT sh.hold_id, sh.count, po.product_option_id, po.add_price, po.size, p.product_id, p.name AS productName, p.origin_price, p.final_price, p.color_name, w.wish_id, s.seller_name, s.base_shipping_fee, s.free_shipping_min_amount, s.extra_shipping_fee, f.file_name, f.store_name, f.file_path, f.copyright, f.copyright_url FROM nextjs_shop_stock_hold sh JOIN nextjs_shop_product_option po ON po.product_option_id = sh.product_option_id JOIN nextjs_shop_product p ON p.product_id = po.product_id LEFT JOIN nextjs_shop_wish w ON w.product_id = p.product_id AND w.user_no = sh.user_no JOIN nextjs_shop_seller s ON s.seller_no = p.seller_no LEFT JOIN ( SELECT pi.product_id, pi.file_id FROM nextjs_shop_product_image pi INNER JOIN ( SELECT product_id, MIN(sort_key) AS min_sort_key FROM nextjs_shop_product_image GROUP BY product_id ) min_pi ON pi.product_id = min_pi.product_id AND pi.sort_key = min_pi.min_sort_key ) tpi ON tpi.product_id = p.product_id LEFT JOIN nextjs_shop_file f ON f.file_id = tpi.file_id WHERE sh.user_no = #{userNo} AND sh.hold_id IN
#{holdId}
AND sh.status = 'HOLD' AND sh.active_hold = 1 AND sh.expires_at > NOW() AND s.approval_status = 'APPROVED' AND po.stock > 0 AND po.is_displayed = 1 AND p.sale_stop = 0 ORDER BY sh.created_at DESC

SELECT shc.hold_coupon_id, shc.hold_id, uc.user_coupon_id, c.coupon_id, c.description, c.coupon_code, c.discount_type, c.discount_value, c.max_discount, c.minimum_order_before_amount, c.is_stackable, c.is_product_restricted, c.amount, c.start_date, c.end_date, c.issue_method, ca.coupon_allowed_id, ca.product_id, s.seller_name FROM nextjs_shop_stock_hold_coupon shc JOIN nextjs_shop_stock_hold sh ON sh.hold_id = shc.hold_id AND sh.status = 'HOLD' AND sh.active_hold = 1 AND sh.expires_at > NOW() AND sh.user_no = #{userNo} JOIN nextjs_shop_product_option po ON po.product_option_id = sh.product_option_id JOIN nextjs_shop_product p ON po.product_id = p.product_id JOIN nextjs_shop_user_coupon uc ON shc.user_coupon_id = uc.user_coupon_id AND uc.used = 0 JOIN nextjs_shop_coupon c ON uc.coupon_id = c.coupon_id AND uc.used = 0 LEFT JOIN nextjs_shop_coupon_allowed ca ON ca.coupon_id = c.coupon_id AND ca.product_id = p.product_id LEFT JOIN nextjs_shop_seller s ON c.seller_no = s.seller_no WHERE shc.hold_id IN
#{holdId}
AND c.is_deleted = 0 AND c.status = 'ACTIVE' AND c.amount > 0 AND ( c.is_product_restricted = 0 OR ca.product_id IS NOT NULL ) AND ( c.issue_method = 'CLAIM' OR (c.issue_method IN ('MANUAL','AUTO') AND uc.user_coupon_id IS NOT NULL) )

mapper.update:
UPDATE nextjs_shop_user_address
SET default_address = 1, usedate_at = NOW()
WHERE user_no = #{userNo} AND address_id = #{addressId}

mapper.select:
SELECT mileage
FROM nextjs_shop_user
WHERE user_no = #{userNo}

mapper.update:
UPDATE nextjs_shop_product_option po JOIN nextjs_shop_stock_hold sh ON sh.product_option_id = po.product_option_id SET po.stock = po.stock - sh.count, po.sales_count = po.sales_count + sh.count WHERE sh.hold_id IN
#{holdId}
AND po.stock >= sh.count AND sh.status = 'HOLD' AND sh.active_hold = 1 AND sh.expires_at > NOW()

UPDATE nextjs_shop_user_coupon SET used = 1, used_at = NOW() WHERE user_coupon_id IN
#{userCouponId}
AND used = 0

UPDATE nextjs_shop_user
SET mileage = mileage - #{usedMileage}
WHERE user_no = #{userNo} AND mileage >= #{usedMileage}

UPDATE nextjs_shop_stock_hold SET status = 'PAY', active_hold = 0 WHERE hold_id IN
#{holdId}
AND status = 'HOLD' AND active_hold = 1 AND expires_at > NOW()

UPDATE nextjs_shop_cart
SET is_deleted = 1
WHERE cart_id IN
(
	SELECT cart_id
	FROM nextjs_shop_stock_hold
	WHERE hold_id IN

		#{holdId}

	AND user_no = #{userNo}
)
 AND user_no = #{userNo}

UPDATE nextjs_shop_user_address
SET usedate_at = NOW()
WHERE address_id = #{addressId} AND user_no = #{userNo}
